#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use Text::Unidecode;

# Function to extract text from a PDF
sub extract_text {
    my ($filename) = @_;

    # Open the PDF file
    my $pdf = PDF::API2->open($filename);

    # Iterate through all pages
    my $text = '';
    for (my $page = 1; $page <= $pdf->pages; $page++) {
        my $page_obj = $pdf->page($page);
        my $textpage = $page_obj->textpage;

        # Extract text from the page
        while (my $line = $textpage->textline) {
            $text .= $line->text . "\n";
        }
    }

    return $text;
}

# Function to find specific data
sub find_data {
    my ($text) = @_;

    # Extract date (simplified regex)
    if ($text =~ /Date:\s*(\d{1,2}\/\d{1,2}\/\d{4})/) {
        print "Date: $1\n";
    }

    # Extract author (simplified regex)
    if ($text =~ /Author:\s*(\w+)/) {
        print "Author: $1\n";
    }

    # Extract table information (simple example)
    $text =~ s/\s+//g; # Remove spaces
    if ($text =~ /(\d{1,3}(,\d{3})*\.\d+)/) {
        print "Table Information: $1\n";
    }
}

